import json, re, collections
arts=[json.loads(l) for l in open('articles/2025/12/27/articles.jsonl')]
patterns={
 'afcon': re.compile(r'AFCON|Africa Cup|Morocco|Nigeria|Senegal|Congo|Tunisia|Algeria|Mali|Zambia|Benin|Botswana', re.I),
 'somalia': re.compile(r'Somalia|Somaliland|Israel|Ethiopia', re.I),
