 'kyiv_embassy': re.compile(r'embassy|Kyiv|Kiev|damaged|Azerbaijan', re.I),
}
for name,pat in patterns.items():
    hits=[]
    for a in arts:
        txt=(a.get('title') or '')+' '+(a.get('content') or '')
        if pat.search(txt):
            hits.append(a.get('title'))
    print(name, len(hits))
    for t,c in collections.Counter(hits).most_common(12):
        print(' -', t)
